import React from 'react';
import './Footer.css';
import logo from '../logoSmall.svg';

const Footer = () => {
  return (
    <footer className="footer" id="contact">
      <div className="footer__inner container">
        <div className="footer__brand">
          <div className="footer__logo">
            <span className="footer__logo-icon">K</span>
            <span className="footer__logo-text">КОРД</span>
          </div>
          <p className="footer__tagline">ГУР МО України</p>
        </div>

        <nav className="footer__nav">
          <a href="#about">Про нас</a>
          <a href="#specializations">Спеціалізації</a>
          <a href="#why">Переваги</a>
          <a href="#join">Долучитись</a>
        </nav>

        <div className="footer__copy">
          <span>© КОРД, ГУР МО України</span>
          <span>II Загін Спеціальних Дій</span>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
